   321→/**
   322→ * HTTP ext_authz filter. Depending on the route configuration, this filter calls the global
   323→ * ext_authz service before allowing further filter iteration.
   324→ */
   325→class Filter : public Logger::Loggable<Logger::Id::ext_authz>,
   326→               public Http::StreamFilter,
   327→               public Filters::Common::ExtAuthz::RequestCallbacks {
   328→public:
   329→  Filter(const FilterConfigSharedPtr& config, Filters::Common::ExtAuthz::ClientPtr&& client)
   330→      : config_(config), client_(std::move(client)), stats_(config->stats()) {}
   331→
   332→  // Http::StreamFilterBase
   333→  void onDestroy() override;
   334→
   335→  // Http::StreamDecoderFilter
   336→  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
   337→                                          bool end_stream) override;
   338→  Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
   339→  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
   340→  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override;
   341→
   342→  // Http::StreamEncoderFilter
   343→  Http::Filter1xxHeadersStatus encode1xxHeaders(Http::ResponseHeaderMap& headers) override;
   344→  Http::FilterHeadersStatus encodeHeaders(Http::ResponseHeaderMap& headers,
   345→                                          bool end_stream) override;
   346→  Http::FilterDataStatus encodeData(Buffer::Instance& data, bool end_stream) override;
   347→  Http::FilterTrailersStatus encodeTrailers(Http::ResponseTrailerMap& trailers) override;
   348→  Http::FilterMetadataStatus encodeMetadata(Http::MetadataMap& trailers) override;
   349→  void setEncoderFilterCallbacks(Http::StreamEncoderFilterCallbacks& callbacks) override;
   350→
   351→  // ExtAuthz::RequestCallbacks
   352→  void onComplete(Filters::Common::ExtAuthz::ResponsePtr&&) override;
   353→
   354→private:
   355→  // Convenience function for the following:
   356→  // 1. If `validate_mutations` is set to true, validate header key and value.
   357→  // 2. If `decoder_header_mutation_rules` is set, check that mutation is allowed.
   358→  Filters::Common::MutationRules::CheckResult
   359→  validateAndCheckDecoderHeaderMutation(Filters::Common::MutationRules::CheckOperation operation,
   360→                                        absl::string_view key, absl::string_view value) const;
   361→
   362→  // Called when the filter is configured to reject invalid responses & the authz response contains
   363→  // invalid header or query parameters. Sends a local response with the configured rejection status
   364→  // code.
   365→  void rejectResponse();
   366→
   367→  absl::optional<MonotonicTime> start_time_;
   368→  void addResponseHeaders(Http::HeaderMap& header_map, const Http::HeaderVector& headers);
   369→  void initiateCall(const Http::RequestHeaderMap& headers);
   370→  void continueDecoding();
   371→  bool isBufferFull(uint64_t num_bytes_processing) const;
   372→  void updateLoggingInfo();
   373→
   374→  // This holds a set of flags defined in per-route configuration.
   375→  struct PerRouteFlags {
   376→    const bool skip_check_;
   377→    const envoy::extensions::filters::http::ext_authz::v3::CheckSettings check_settings_;
   378→  };
   379→  PerRouteFlags getPerRouteFlags(const Router::RouteConstSharedPtr& route) const;
   380→
   381→  // State of this filter's communication with the external authorization service.
   382→  // The filter has either not started calling the external service, in the middle of calling
   383→  // it or has completed.
   384→  enum class State { NotStarted, Calling, Complete };
   385→
   386→  // FilterReturn is used to capture what the return code should be to the filter chain.
   387→  // if this filter is either in the middle of calling the service or the result is denied then
   388→  // the filter chain should stop. Otherwise, the filter chain can continue to the next filter.
   389→  enum class FilterReturn { ContinueDecoding, StopDecoding };
   390→
