   107→      pool_(scope_.symbolTable()),
   108→      metadata_context_namespaces_(config.metadata_context_namespaces().begin(),
   109→                                   config.metadata_context_namespaces().end()),
   110→      typed_metadata_context_namespaces_(config.typed_metadata_context_namespaces().begin(),
   111→                                         config.typed_metadata_context_namespaces().end()),
   112→      route_metadata_context_namespaces_(config.route_metadata_context_namespaces().begin(),
