   151→    if (config.http_service().authorization_request().has_allowed_headers()) {
   152→      allowed_headers_matcher_ = Filters::Common::ExtAuthz::CheckRequestUtils::toRequestMatchers(
   153→          config.http_service().authorization_request().allowed_headers(), true, factory_context);
