    34→message ExtAuthz {
    35→  option (udpa.annotations.versioning).previous_message_type =
    36→      "envoy.config.filter.http.ext_authz.v3.ExtAuthz";
    37→
    38→  reserved 4;
    39→
    40→  reserved "use_alpha";
    41→
    42→  // External authorization service configuration.
    43→  oneof services {
    44→    // gRPC service configuration (default timeout: 200ms).
    45→    config.core.v3.GrpcService grpc_service = 1;
    46→
    47→    // HTTP service configuration (default timeout: 200ms).
    48→    HttpService http_service = 3;
    49→  }
    50→
    51→  // API version for ext_authz transport protocol. This describes the ext_authz gRPC endpoint and
    52→  // version of messages used on the wire.
    53→  config.core.v3.ApiVersion transport_api_version = 12
    54→      [(validate.rules).enum = {defined_only: true}];
    55→
    56→  //  Changes filter's behaviour on errors:
    57→  //
    58→  //  1. When set to true, the filter will ``accept`` client request even if the communication with
    59→  //  the authorization service has failed, or if the authorization service has returned a HTTP 5xx
    60→  //  error.
    61→  //
    62→  //  2. When set to false, ext-authz will ``reject`` client requests and return a ``Forbidden``
    63→  //  response if the communication with the authorization service has failed, or if the
    64→  //  authorization service has returned a HTTP 5xx error.
    65→  //
    66→  // Note that errors can be ``always`` tracked in the :ref:`stats
    67→  // <config_http_filters_ext_authz_stats>`.
    68→  bool failure_mode_allow = 2;
    69→
    70→  // When ``failure_mode_allow`` and ``failure_mode_allow_header_add`` are both set to true,
    71→  // ``x-envoy-auth-failure-mode-allowed: true`` will be added to request headers if the communication
    72→  // with the authorization service has failed, or if the authorization service has returned a
    73→  // HTTP 5xx error.
    74→  bool failure_mode_allow_header_add = 19;
